            return null;
        }
        for (PensioenPijler2TypeBijdrage value : PensioenPijler2TypeBijdrage.values()) {
            if (value.getCode().equals(code)) {
                return value;
            }
        }
        throw new EnumTypeNotFoundException("No PensioenPijler2TypeBijdrage with a corresponding code found for " + code);
    }

    public static List<PensioenPijler2TypeBijdrage> getByGroep(PensioenPijler2TypeBijdrageGroep groep) {
