        for (PensioenPijler2TypeBijdrage value : PensioenPijler2TypeBijdrage.values()) {
            if (value.getGroep().equals(groep)) {
                bijdrages.add(value);
            }
        }
        return bijdrages;
    }

    public static boolean isAntwerpen(int code) {
        return code == PensioenPijler2TypeBijdrage.ANTWERPEN.getCode();
    }

    public boolean isGeldig(RekenTijd rekenTijd) {
        return groep.isGeldig(rekenTijd);
    }

    public boolean isProvantOrEthias() {
        return this == PROVANT || this == ETHIAS;
